def read_safe(filepath: Union[str, Path], encoding: str = "utf-8") -> str:
        """
        Reads content from a file safely.
        If reading the primary file fails, attempts to read from the backup (.bak).

        Args:
            filepath: Target file path.
            encoding: File encoding.

        Returns:
            str: File content.

        Raises:
            FileNotFoundError: If neither file nor backup exists.
            IOError: If reading fails.
        """
        target_path = Path(filepath)
        backup_path = target_path.with_suffix(target_path.suffix + ".bak")

        # Attempt 1: Read original
        if target_path.exists():
            try:
                with open(target_path, "r", encoding=encoding) as f:
                    return f.read()
            except Exception as e:
                logger.error(f"Failed to read {target_path}: {e}")
                if not backup_path.exists():
                    raise IOError(
                        f"Failed to read {target_path} and no backup found: {e}"
                    )
                # Fallthrough to backup
        elif not backup_path.exists():
            raise FileNotFoundError(f"File not found: {target_path}")

        # Attempt 2: Read backup
        if backup_path.exists():
            logger.warning(f"Attempting to read from backup: {backup_path}")
            try:
                with open(backup_path, "r", encoding=encoding) as f:
                    return f.read()
            except Exception as e:
                raise IOError(f"Failed to read backup {backup_path}: {e}")

        raise IOError(f"Unknown error reading {target_path}")

def format_for_report(self) -> str:
        """Format trace as markdown for inclusion in the final report."""
        if not self.steps:
            return ""
        lines = ["## Reasoning Trace\n"]
        for step in self.steps:
            lines.append(f"### Iteration {step.iteration}")
            if step.learned:
                lines.append("**Learned:**")
                lines.extend(f"- {x}" for x in step.learned)
            if step.contradictions:
                lines.append("**Contradictions:**")
                lines.extend(f"- ⚠️ {x}" for x in step.contradictions)
            if step.refutations:
                lines.append("**Refutations (Phase Inversion):**")
                lines.extend(f"- 🔄 {x}" for x in step.refutations)
            if step.gaps:
                lines.append("**Open questions:**")
                lines.extend(f"- ❓ {x}" for x in step.gaps)
            lines.append(
                f"**Confidence:** {step.confidence:.0%} | "
                f"**Info gain:** {step.info_gain:.3f} | "
                f"**New results:** {step.new_results}"
            )
            lines.append("")
        return "\n".join(lines)

