def product(*args: Any) -> List[Tuple]:
    """展開 (%) — 全次元の組み合わせを保持

    CCL: A % B
    圏論: Anamorphism (unfold) — F-余代数的生成 (β: A → F(A))
    """
    if not args:
        return []

    # 各引数をイテラブルに変換
    iterables = []
    for a in args:
        if isinstance(a, (list, tuple, set)):
            iterables.append(a)
        elif isinstance(a, dict):
            iterables.append(list(a.items()))
        else:
            iterables.append([a])

    return list(itertools.product(*iterables))

