def analyze_layer_differentiation(
    all_layer_vecs: list[dict[int, np.ndarray]],
    num_layers: int,
) -> dict:
    """層間の分化度を多角的に分析。

    指標:
    1. 隣接層間 cosine sim の平均 (低い = 層間分化が大きい)
    2. 最浅↔最深 cosine sim (低い = 端間分化が大きい)
    3. 層間 sim の標準偏差 (高い = 層に応じて分化度が異なる)
    4. Layer Pair Sweep (run_layer_sweep.py と同等)
    """
    n_texts = len(all_layer_vecs)
    if n_texts < 2:
        return {"error": "テキスト数不足"}

    # 1. 隣接層間 sim (各テキストで L_i ↔ L_{i+1} の平均)
    adjacent_sims = []
    for layer_idx in range(1, num_layers):
        text_sims = []
        for vecs in all_layer_vecs:
            if layer_idx in vecs and (layer_idx + 1) in vecs:
                text_sims.append(cosine_sim(vecs[layer_idx], vecs[layer_idx + 1]))
        if text_sims:
            adjacent_sims.append(np.mean(text_sims))

    # 2. 最浅↔最深 sim
    endpoint_sims = []
    for vecs in all_layer_vecs:
        if 1 in vecs and num_layers in vecs:
            endpoint_sims.append(cosine_sim(vecs[1], vecs[num_layers]))

    # 3. 全ペアの sim マトリクスから layer distance を計算
    # Layer Distance = 1 - mean cos_sim(L_i text_a, L_j text_a) for text_a
    layer_sim_matrix = np.zeros((num_layers, num_layers))
    for i in range(1, num_layers + 1):
        for j in range(1, num_layers + 1):
            sims = []
            for vecs in all_layer_vecs:
                if i in vecs and j in vecs:
                    sims.append(cosine_sim(vecs[i], vecs[j]))
            if sims:
                layer_sim_matrix[i - 1, j - 1] = np.mean(sims)

    # 4. Precision sweep — 代表的な層ペアで precision range を計算
    # 対称的な位置のペア: (1, N), (2, N-1), (N//4, 3N//4), (N//2-1, N//2)
    layer_pairs = {}
    n = num_layers
    candidates = [
        (f"L1↔L{n}", [1], [n]),
        (f"L2↔L{n-1}", [2], [n - 1]),
        (f"L{n//4}↔L{3*n//4}", [n // 4], [3 * n // 4]),
        (f"L{n//2}↔L{n//2+1}", [n // 2], [n // 2 + 1]),
        (f"L1-2↔L{n-1}-{n}", [1, 2], [n - 1, n]),
    ]
    for name, shallow, deep in candidates:
        sims = _compute_pair_sims(all_layer_vecs, shallow, deep)
        if len(sims) >= 2:
            p_vals = _normalize_to_precision(sims)
            layer_pairs[name] = {
                "sim_mean": float(np.mean(sims)),
                "sim_std": float(np.std(sims)),
                "precision_range": float(np.max(p_vals) - np.min(p_vals)),
                "precision_std": float(np.std(p_vals)),
                "precision_values": [round(v, 4) for v in p_vals],
            }

    return {
        "adjacent_sim_mean": float(np.mean(adjacent_sims)) if adjacent_sims else None,
        "adjacent_sim_std": float(np.std(adjacent_sims)) if adjacent_sims else None,
        "endpoint_sim_mean": float(np.mean(endpoint_sims)) if endpoint_sims else None,
        "endpoint_sim_std": float(np.std(endpoint_sims)) if endpoint_sims else None,
        "sim_matrix_mean": float(np.mean(layer_sim_matrix[layer_sim_matrix > 0])),
        "sim_matrix_range": float(
            np.max(layer_sim_matrix[layer_sim_matrix > 0])
            - np.min(layer_sim_matrix[layer_sim_matrix > 0])
        ) if np.any(layer_sim_matrix > 0) else 0.0,
        "layer_pairs": layer_pairs,
    }

def _write_buffer(self) -> None:
        """Write the buffer to the output file."""

        with self._lock:
            if self.record and not self._buffer_index:
                with self._record_buffer_lock:
                    self._record_buffer.extend(self._buffer[:])

            if self._buffer_index == 0:
                if self.is_jupyter:  # pragma: no cover
                    from .jupyter import display

                    display(self._buffer, self._render_buffer(self._buffer[:]))
                    del self._buffer[:]
                else:
                    if WINDOWS:
                        use_legacy_windows_render = False
                        if self.legacy_windows:
                            fileno = get_fileno(self.file)
                            if fileno is not None:
                                use_legacy_windows_render = (
                                    fileno in _STD_STREAMS_OUTPUT
                                )

                        if use_legacy_windows_render:
                            from rich._win32_console import LegacyWindowsTerm
                            from rich._windows_renderer import legacy_windows_render

                            buffer = self._buffer[:]
                            if self.no_color and self._color_system:
                                buffer = list(Segment.remove_color(buffer))

                            legacy_windows_render(buffer, LegacyWindowsTerm(self.file))
                        else:
                            # Either a non-std stream on legacy Windows, or modern Windows.
                            text = self._render_buffer(self._buffer[:])
                            # https://bugs.python.org/issue37871
                            # https://github.com/python/cpython/issues/82052
                            # We need to avoid writing more than 32Kb in a single write, due to the above bug
                            write = self.file.write
                            # Worse case scenario, every character is 4 bytes of utf-8
                            MAX_WRITE = 32 * 1024 // 4
                            try:
                                if len(text) <= MAX_WRITE:
                                    write(text)
                                else:
                                    batch: List[str] = []
                                    batch_append = batch.append
                                    size = 0
                                    for line in text.splitlines(True):
                                        if size + len(line) > MAX_WRITE and batch:
                                            write("".join(batch))
                                            batch.clear()
                                            size = 0
                                        batch_append(line)
                                        size += len(line)
                                    if batch:
                                        write("".join(batch))
                                        batch.clear()
                            except UnicodeEncodeError as error:
                                error.reason = f"{error.reason}\n*** You may need to add PYTHONIOENCODING=utf-8 to your environment ***"
                                raise
                    else:
                        text = self._render_buffer(self._buffer[:])
                        try:
                            self.file.write(text)
                        except UnicodeEncodeError as error:
                            error.reason = f"{error.reason}\n*** You may need to add PYTHONIOENCODING=utf-8 to your environment ***"
                            raise

                    self.file.flush()
                    del self._buffer[:]

