def _parse_tagged_block(self, expr: str) -> 'TaggedBlock':
        """意味タグ付きブロックをパース: V:{body}, C:{body}, R:{body}, M:{body}, E:{body}"""
        tag = expr[0]  # V, C, R, M, or E
        # tag:{ の後の body を抽出 (ネストしたブラケットを考慮)
        if not expr[2] == '{':
            raise ValueError(f"Invalid tagged block: {expr}")

        # ネストした {} を考慮して body を抽出
        depth = 0
        body_start = 2  # ':' の次の '{'
        body_end = -1
        for i in range(body_start, len(expr)):
            if expr[i] == '{':
                depth += 1
            elif expr[i] == '}':
                depth -= 1
                if depth == 0:
                    body_end = i
                    break

        if body_end == -1:
            raise ValueError(f"Unmatched braces in tagged block: {expr}")

        body_str = expr[body_start + 1:body_end].strip()
        body = self._parse_expression(body_str)

        # タグブロック後に続く式がある場合（例: V:{/dia}_I:[pass]{...}）
        rest = expr[body_end + 1:].strip()
        if rest:
            # 残りの部分（通常は _ で接続されている）を処理
            if rest.startswith('_'):
                rest = rest[1:].strip()
            rest_node = self._parse_expression(rest)
            tagged = TaggedBlock(tag=tag, body=body)
            return Sequence(steps=[tagged, rest_node])

        return TaggedBlock(tag=tag, body=body)

def score_subscribers(
        self,
        event: CognitionEvent,
        event_type: Optional[EventType] = None,
    ) -> List[Dict[str, Any]]:
        """全アクティブ subscriber のスコアを計算し、降順で返す (Phase 3)

        FEP 同型: EFE argmin と同じ構造。
        各モジュールが自身の「情報価値」を自己評価し、
        最も高いスコアのモジュールが選択される。

        Returns:
            [{"subscriber": sub, "name": name, "score": float}, ...] (降順)
        """
        if not self.enabled:
            return []

        et = event_type or event.event_type
        candidates = (
            self._subscribers.get(et, [])
            + self._global_subscribers
        )

        scored = []
        for sub in candidates:
            try:
                # should_activate でフィルタ (Phase 2 の前段フィルタ)
                if hasattr(sub, 'should_activate'):
                    if not sub.should_activate(event):
                        continue

                # score() を持つ subscriber のみスコアリング
                if hasattr(sub, 'score'):
                    s = sub.score(event)
                else:
                    s = 0.5  # デフォルト

                sub_name = getattr(sub, 'name', sub.__class__.__name__)
                scored.append({
                    "subscriber": sub,
                    "name": sub_name,
                    "score": s,
                })
            except Exception as e:
                logger.debug("EventBus: score failed for %s: %s", sub, e)

        # スコア降順でソート
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored

def unsubscribe(
        self,
        event_type: EventType,
        subscriber: EventSubscriber,
    ) -> None:
        """subscriber を登録解除"""
        subs = self._subscribers.get(event_type, [])
        if subscriber in subs:
            subs.remove(subscriber)

