def _fallback_generate(self, prompt: str) -> str:
        """フォールバック生成 (LLM なし)"""
        if self.role == AgentRole.PROPOSER:
            return "この主張は論理的に妥当であり、支持できる。"
        elif self.role == AgentRole.CRITIC:
