def _extract_braced_body(self, s: str) -> tuple:
        """先頭の {body} を抽出 (ネスト対応)。

        Returns:
            (body_str, rest) — body_str は {} 内の文字列、rest は残りの文字列。
            body_str が None の場合は抽出失敗。
        """
        s = s.strip()
        if not s or s[0] != '{':
            return (None, s)

        depth = 0
        for i, c in enumerate(s):
            if c == '{':
                depth += 1
            elif c == '}':
                depth -= 1
                if depth == 0:
                    body = s[1:i].strip()
                    rest = s[i+1:].strip()
                    return (body, rest)

        return (None, s)

