def executor(self):
        """エグゼキューターを取得 (遅延初期化)"""
        if self._executor is None:
            from .executor import WorkflowExecutor
            self._executor = WorkflowExecutor()
        return self._executor

def load_all(self) -> Dict[str, WorkflowDefinition]:
        """全ワークフローをロード (サブディレクトリ再帰対応)"""
        result = {}

        for search_path in self.search_paths:
            if not search_path.exists():
                continue

            for path in search_path.rglob("*.md"):
                if path.name.startswith("_"):
                    continue  # _ で始まるファイルはスキップ

                # _プレフィックスのディレクトリ配下はスキップ
                rel = path.relative_to(search_path)
                if any(p.name.startswith("_") for p in rel.parents if p != Path(".")):
                    continue

                name = path.stem
                if name not in result:
                    try:
                        result[name] = self.parser.parse(path)
                    except Exception:
                        continue  # パース失敗はスキップ

        self._cache.update(result)
        return result

def _build_if_condition(self, if_cond: Any) -> str:
        """IfCondition を分岐で構築"""
        then_id = self._build_node(if_cond.then_branch)
        else_id = self._build_node(if_cond.else_branch) if if_cond.else_branch else None

        node_id = self._new_node_id("branch")
        children = [then_id]
        if else_id:
            children.append(else_id)

        self.nodes[node_id] = GraphNode(
            id=node_id,
            type=NodeType.BRANCH,
            children=children,
            metadata={
                "condition": {
                    "var": if_cond.condition.var,
                    "op": if_cond.condition.op,
                    "value": if_cond.condition.value
                }
            }
        )

        return node_id

