def apply_response(
        self,
        response: HITLResponse,
        state: Dict[str, Any]
    ) -> Dict[str, Any]:
        """レスポンスを状態に適用"""
        new_state = state.copy()

        if response.command == HITLCommand.MODIFY and response.state_modifications:
            new_state.update(response.state_modifications)

        if response.user_input:
            if "user_inputs" not in new_state:
                new_state["user_inputs"] = []
            new_state["user_inputs"].append(response.user_input)

        return new_state

async def _heartbeat_http():
        count = 0
        while True:
            await asyncio.sleep(30)
            count += 1
            print(f"[hermeneus] heartbeat #{count} (event loop alive)", file=sys.stderr, flush=True)
            try:
                violations = check_pending_dispatches()
                for v in violations:
                    print(f"[hermeneus] 🚨 θ12.1 WBC Alert: dispatch({v['ccl']}) pending for {v['elapsed_sec']}s", file=sys.stderr, flush=True)
            except Exception as e:
                print(f"[hermeneus] Failed to check pending dispatches: {e}", file=sys.stderr, flush=True)

